bodyStatements.text:
for i: int := 0 to |a|
  invariant |p| + |s2| == i
  invariant |p| == |seen|
  invariant forall j: int {:trigger p[j]} | 0 <= j < |p| :: 1 <= p[j] && p[j] <= n
  invariant forall j: int, k: int {:trigger p[k], p[j]} | 0 <= j < k < |p| :: p[j] != p[k]
  invariant forall x: int {:trigger x in p} {:trigger x in seen} | x in seen :: x in p
  invariant forall x: int {:trigger x in seen} {:trigger x in p} | x in p :: x in seen
  invariant |s2| <= |p|
  invariant forall j: int {:trigger p[j]} {:trigger s2[j]} | 0 <= j < |s2| :: s2[j] == p[j]
  invariant IsMerge(a[..i], p, s2)
{
  if a[i] !in seen {
    MergeAppendS1(a[..i], p, s2, a[i]);
    p := p + [a[i]];
    seen := seen + {a[i]};
  } else {
    assume {:axiom} |s2| < |p| && a[i] == p[|s2|];
    MergeAppendS2(a[..i], p, s2, a[i]);
    s2 := s2 + [a[i]];
  }
}
